window.__QUIZ_DATA__=[{"id":"objective>Physics>1996>1","subject":"Physics","year":"1996","type":"Objective","topic":"FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : FUNDAMENTAL QUANTITIES AND UNITS","question":"The diagram below represents a portion of a micrometer screw gauge in which the horizontal scale is in millimetre. What is the reading on the instrument?","images":["data:image/png;base64,"],"options":{"A":"3.72 mm","B":"3.50 mm","C":"3.30 mm","D":"3.22 mm"},"answer":"D","explanation":"3+22100=3+0.22=3.22mm  \u2234 the reading on the instrument is 3.22 mm","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>2","subject":"Physics","year":"1996","type":"Objective","topic":"FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES\u2019 PRINCIPLE","question":"A loaded test-tube which floats upright in water is carefully and slightly depressed and then released. Which of the following best describes the subsequent motion of the test-tube?","images":[],"options":{"A":"Circular","B":"Rotational","C":"Random","D":"Oscillatory"},"answer":"D","explanation":"A loaded test-tube slightly depressed and released undergoes a simple harmonic motion which is an oscillatory motion","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>3","subject":"Physics","year":"1996","type":"Objective","topic":"MOTION : TYPES OF MOTION","question":"The dagram above illustrates the velocity-time graph of the motion of a body. Calculate the total distance travelled by the body.","images":["data:image/png;base64,"],"options":{"A":"50 m","B":"65 m","C":"175 m","D":"225 m"},"answer":"D","explanation":"Distance covered by the body = Trapezium A + Rectangle B + Triangle C    ==> Trapezium A = 1/2(a + b)h = 1/2(10 + 20)5 = 1/2(30)5 = 15 x 5 = 75 m    Rectangle B = L x B = 20 x 5 = 100 m    Triangle C = 1/2bh = 1/2 x 5 x 20 = 5 x 10 = 50 m    \u2234 Total distance = 75 + 100 + 50 = 225 m","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>4","subject":"Physics","year":"1996","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A ball of mass 5.0 kg hits a smooth vertical wall normally with a speed of 2 ms-1 and rebounds with the same speed. Determine the impulse experienced by the ball.","images":[],"options":{"A":"20.0 kgms-1","B":"10.0 kgms-1","C":"5.0 kgms-1","D":"0.0 kgms-1"},"answer":"A","explanation":"Impulse is the change in momentum of an object when the object is acted upon by a force for an interval of time. In this case, the ball hits the wall and rebounds with the same speed but in the opposite direction. So, the change in momentum is 2*5 (initial momentum) + 2*5 (final momentum) = 20 kgms-1.","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>5","subject":"Physics","year":"1996","type":"Objective","topic":"GRAVITATIONAL FIELD : GRAVITATIONAL POTENTIAL AND ESCAPE VELOCITY","question":"A rocket is launched from the surface of the earth. If the radius of the earth is 4.6 x 106 m and the acceleration of free fall due to gravity is 10 ms-2, calculate the escape velocity of the rocket.","images":[],"options":{"A":"2.53 x 104 ms-1","B":"9.6 x 103 ms-1","C":"8.00 x 103 ms-1","D":"4.23 x 103 ms-1"},"answer":"B","explanation":"r = 4.6 x 106 m; g = 10 ms-2; v = ?  escape velocity = \u221a2gr = \u221a(2 x 10 x 4.6 x 106)  = \u221a(92 x 106) = 9.6 x 103 ms-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>6","subject":"Physics","year":"1996","type":"Objective","topic":"MACHINES :","question":"The velocity ratio and efficiency of a system of pulleys are 6 and 80% respectively. How much effort is required to lift a load of mass 120 kg with this system.  [g = 10 ms-2]","images":[],"options":{"A":"25 N","B":"90 N","C":"96 N","D":"250 N"},"answer":"D","explanation":"V.R = 6; \u03b5 = 80%; E = ?; L = 120 kg = 120 x 10 = 1200 N; g = 10 ms-2; \u03b5 = L/E x 1/V.R x 100%   80%=1200Ex16x100%  =80=1200Ex16x100  =80100=12006E  =80x6E=1200x100  =480E=120000  =E=120000480  \u2234E=250N","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>7","subject":"Physics","year":"1996","type":"Objective","topic":"MACHINES :","question":"Two spanners X and Y of lengths 15 cm and 20 cm respectively are used in turn to give a screw of pitch 2 mm one complete rotation. If RX and RY are the respective velocity ratios of the spanners, the the ratio RX : RY is","images":[],"options":{"A":"1 : 50","B":"3 : 20","C":"3 : 4","D":"4 : 3"},"answer":"C","explanation":"[Let your units be in cm]  IfRX=2\u03c0ap=2\u03c0 x 150.2andRY=2\u03c0ap=2\u03c0 x 200.2  RX:RY=2\u03c0 x 150.2:2\u03c0 x 200.2=2\u03c0x75:2\u03c0x100=3:4","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>8","subject":"Physics","year":"1996","type":"Objective","topic":"MOTION : SIMPLE IDEAS OF CIRCULAR MOTION","question":"The magnitude of the force required to make an object of mass M move with a speed V in a circular path of radius R is given by the expression","images":[],"options":{"A":"mrv","B":"(mr)2v","C":"mv2r","D":"mvr2"},"answer":"C","explanation":"The force required to make an object of mass M move with a speed V in a circular path of radius R is given by the centripetal force formula F = mv^2/r. Therefore, the correct answer is mv^2/r.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>9","subject":"Physics","year":"1996","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A body of mass 4.2 kg moving with velocity 10 ms-1 due east, hits a stationary body of mass 2.8 kg. If they stick together after collision and move with velocity V due east, calculate the value of V.","images":[],"options":{"A":"3 ms-1","B":"6 ms-1","C":"7 ms-1","D":"15 ms-1"},"answer":"B","explanation":"m1 = 4.2 kg; u1 = 10 ms-1; u2 = 0; m2 = 2.8 kg; v = ?  momentum before collision = momentum after collision  m1u1 + m2u2 = (m1 + m2)v [v1 = v2 = v since the bodies stick together after collision]  = 4.2 x 10 = (4.2 + 2.8)v  = 42 = 7v  \u2234v=427=6ms-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>10","subject":"Physics","year":"1996","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A body of mass 2 kg is suspended from the ceiling of a lift with light inextensible string. If the lift moves upwards with acceleration of 2ms-2, calculate the magnitude of the tension in the string.  [g = 10 ms-2]","images":[],"options":{"A":"24 N","B":"20 N","C":"16 N","D":"4 N"},"answer":"A","explanation":"The tension in the string is the force that balances the weight of the body and the force due to the acceleration of the lift. The weight of the body is its mass times the acceleration due to gravity, which is 2 kg * 10 m/s^2 = 20 N. The force due to the acceleration of the lift is the mass of the body times the acceleration of the lift, which is 2 kg * 2 m/s^2 = 4 N. Therefore, the tension in the string is 20 N + 4 N = 24 N.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>11","subject":"Physics","year":"1996","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A stationary object of mass 4 kg is set in motion by a net force of 50 N. If the object attains a speed of 5 ms-1 in time t. Calculate the value of t.","images":[],"options":{"A":"0.20 s","B":"0.40 s","C":"0.63 s","D":"0.80 s"},"answer":"B","explanation":"F = 50 N; m = 4 kg; u = 0; v = 5 ms-1; t = ?  F=ma;a=Fm=504=12.5ms-2  v = u + at  = 5 = 0 + 12.5t  = 5 = 12.5t  \u2234t=512.5=0.40s","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>12","subject":"Physics","year":"1996","type":"Objective","topic":"SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M","question":"Two simple pendula X and Y make 400 and 500 oscillations respectively in equal time. If the period of oscillations of X is 1.5 seconds, what is the period of oscillations of Y?","images":[],"options":{"A":"0.53 s","B":"0.83 s","C":"1.20 s","D":"1.50 s"},"answer":"C","explanation":"T=tn;t=Tn  since tX = tY  \u22341.5x400=500xt;t=1.5 x 400500=65=1.20s","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>13","subject":"Physics","year":"1996","type":"Objective","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"A platinum-resistance thermometer has a resistance of 5 \u03a9 at 0oC and 9 \u03a9 at 100oC. Assuming that resistance changes uniformly with temperature, calculate the resistance of the thermometer when the temperature is 45oC.","images":[],"options":{"A":"13.9 \u03a9","B":"8.9 \u03a9","C":"6.8 \u03a9","D":"3.2 \u03a9"},"answer":"C","explanation":"R1 = 5 \u03a9 at 0oC; R2 = 9 \u03a9 at 100oC; R = ? at 45oC  45 - 0100 - 0=R - 59 - 5  45100=R - 54  180100=R-5  1.8 = R - 5  \u2234 R = 1.8 + 5 = 6.8 \u03a9","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>14","subject":"Physics","year":"1996","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"The linear expansivity of a metal P is twice that of another metal Q. When these materials are heated through the same temperature change, their increase in length is the same. Calculate the ratio of the original length of P to that of Q.","images":[],"options":{"A":"1 : 4","B":"1 : 2","C":"2 : 1","D":"4 : 1"},"answer":"B","explanation":"\u03b1P = 2\u03b1Q  \u0394\u03b8P = \u0394\u03b8Q  \u0394LP = \u0394LQ  LP : LQ = ?  \u03b1=\u0394LL\u0394\u03b8  L=\u0394L\u03b1\u0394\u03b8  LP : LQ=\u0394LP\u03b1P\u0394\u03b8P:\u0394LQ\u03b1Q\u0394\u03b8Q  =\u0394LQ2\u03b1Q\u0394\u03b8Q : \u0394LQ\u03b1Q\u0394\u03b8Q  =\u0394LQ2\u03b1Q\u0394\u03b8Q x \u03b1Q\u0394\u03b8Q\u0394LQ = 12  \u2234 LP : LQ = 1 : 2","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>15","subject":"Physics","year":"1996","type":"Objective","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"The pressure of a fixed mass of a gas is 2.0 x 105 Nm-2 at a known temperature. Assuming that the temperature remains constant, what will be the pressure of the gas if its volume is halved?","images":[],"options":{"A":"1.0 x 105 Nm-2","B":"2.0 x 105 Nm-2","C":"3.0 x 105 Nm-2","D":"4.0 x 105 Nm-2"},"answer":"D","explanation":"P1 = 2.0 x 105 Nm-2; V1 = V cm3; V2 = 1/2V1; P1 = ?    P1V1 = P2V2    2.0 x 105 x V = P2 x 1/2V    2.0 x 105 = P2 x 1/2    \u2234 P2 = 2.0 x 105 x 2 = 4.0 x 105 Nm-2","marks":"1","difficulty":"1"},{"id":"objective>Physics>1996>16","subject":"Physics","year":"1996","type":"Objective","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"Which of the following statements is not correct?","images":[],"options":{"A":"Heat energy can be transformed into mechanical energy","B":"The total heat content of a body is the sum of the kinetic energies of its molecules","C":"If a body is heated, its molecules move faster","D":"If a body is cooled, molecular movement remains constant"},"answer":"D","explanation":"The statement 'If a body is cooled, molecular movement remains constant' is incorrect. When a body is cooled, the kinetic energy of its molecules decreases, which results in a decrease in the speed of molecular movement. Therefore, molecular movement does not remain constant when a body is cooled.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1996>17","subject":"Physics","year":"1996","type":"Objective","topic":"HEAT ENERGY : HEAT CAPACITY","question":"A 400 W immersion heater is used to heat a liquid of mass 0.5 kg. If the temperature of the liquid increses by 2.5oC in one second, calculate the specific heat capacity of the liquid. (Neglect heat losses to the sorroundings)","images":[],"options":{"A":"80 Jkg-1K-1","B":"320 Jkg-1K-1","C":"500 Jkg-1K-1","D":"1200 Jkg-1K-1"},"answer":"B","explanation":"P = 400 W; m = 0.5 kg; \u0394\u03b8 = 2.5oC; c = ?; t = 1 s  Pt = mc\u0394\u03b8  = 400 x 1 = 0.5 x c x 2.5  = 400 = 1.25c  \u2234c=4001.25=320Jkg-1K-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>18","subject":"Physics","year":"1996","type":"Objective","topic":"HEAT ENERGY : SPECIFIC LATENT HEAT OF VAPORISATION","question":"What is the difference in the amount of heat given out by 4 kg of steam and 4 kg of water when both are cooled from 100oC to 80oC.  [Specific latent heat of steam = 2,260,000 Jkg-1]  [Specific heat capacity of water = 4,200 Jkg-1K-1]","images":[],"options":{"A":"336,000 J","B":"672,000 J","C":"8,704,000 J","D":"9,040,000 J"},"answer":"D","explanation":"Q of steam = ml + mc\u0394\u03b8  Q of water = mc\u0394\u03b8  [since steam and water have the same mass and temperature difference]  \u2234 Q of steam - Q of water = ml + mc\u0394\u03b8 - (mc\u0394\u03b8) = ml = 4 x 2,260,000 = 9,040,000 J","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>19","subject":"Physics","year":"1996","type":"Objective","topic":"HEAT ENERGY : HEAT TRANSFER","question":"The heating element in an kettle circuit is usually located near the bottom of the kettle because","images":[],"options":{"A":"Water is a good conductor of heat","B":"Heat can be more quickly radiated to all parts of the water","C":"No heat can be lost to the sorroundings","D":"The convectional currents which are set up can carry heat to all parts of the water"},"answer":"D","explanation":"The heating element is at the bottom of an electric kettle so that the water at the bottom, when heated, expands and thus becomes lighter. And as it becomes lighter, it moves up and the heavier ones at the top comes down and the cycle continues thereby setting up convectional flow of currents","marks":"1","difficulty":"1"},{"id":"objective>Physics>1996>20","subject":"Physics","year":"1996","type":"Objective","topic":"HEAT ENERGY : HEAT TRANSFER","question":"The inside of a vacuum flask is usually coated with silver to reduce heat loss by","images":[],"options":{"A":"convection","B":"conduction","C":"radiation","D":"absorption"},"answer":"C","explanation":"It is found that, for a given temperature, a dull black surface radiates most and a highly polished surface radiates least. So, silver being a highly polished surface, prevents heat loss by radiation.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1996>21","subject":"Physics","year":"1996","type":"Objective","topic":"HEAT ENERGY : VAPOUR AND VAPOUR PRESSURE","question":"The saturated vapour pressure of a liquid increases as the","images":[],"options":{"A":"volume of the liquid increases","B":"volume of the liquid decreases","C":"temperature of the liquid increases","D":"temperature of the liquid decreases"},"answer":"C","explanation":"The saturated vapour pressure of a liquid is the pressure exerted by a vapour in thermodynamic equilibrium with its condensed phases at a given temperature. It increases as the temperature of the liquid increases because the molecules have more kinetic energy to escape from the liquid surface and become a gas.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>22","subject":"Physics","year":"1996","type":"Objective","topic":"HEAT ENERGY : HUMIDITY AND THE WEATHER","question":"Cloud formation is the direct result of","images":[],"options":{"A":"precipitation","B":"vaporisation","C":"fusion","D":"sublimation"},"answer":"B","explanation":"Cloud formation is the direct result of vaporisation. When water on the earth's surface is heated by the sun, it evaporates to form water vapour. This water vapour rises, cools, and condenses to form clouds.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>23","subject":"Physics","year":"1996","type":"Objective","topic":"HEAT ENERGY : BOILING POINT","question":"Water boils at a lower temperature when heated at the top of a mountain that at sea-level because at the top of the mountain the","images":[],"options":{"A":"saturation vapour pressure of water is higher than at sea-level","B":"sun adds more heat to the water","C":"temperature is lower than at sea level","D":"pressure of the atmosphere is lower"},"answer":"D","explanation":"Liquid boils at a lower temperature at the top of a mountain than at sea level.  This is because the pressure at the top of a mountain is low. As the pressure is lowered, the boiling point is lowered","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>24","subject":"Physics","year":"1996","type":"Objective","topic":"HEAT ENERGY : BOILING POINT","question":"The main reason why rice cooks faster in pressure cooker than in cooking pot is that","images":[],"options":{"A":"less heat escapes from the cooker","B":"the vapour pressure of the cooker is constant","C":"the rice is not affected by the draught over the cooker","D":"The boiling point of water in the cooker is raised"},"answer":"D","explanation":"\u200bFood cooks faster in a pressure cooker. Its because the pressure increases inside the cooker, which also increases the boiling point of water. \u200bSo, more heat is required to reach the boiling point and is sufficient to cook food in a reduced time","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>25","subject":"Physics","year":"1996","type":"Objective","topic":"SOUND WAVES : SPEED OF SOUND","question":"In which of the following media would sound waves travel fastest?","images":[],"options":{"A":"Kerosene","B":"Air","C":"Water","D":"Iron"},"answer":"D","explanation":"Sound travels faster in solids as compared to liquids and gases as the particles are more tightly packed. The closer the molecules, the tighter their bonds, the less time it take to reach to other molecules.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>26","subject":"Physics","year":"1996","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"A ray of light strikes a plane mirror at a glancing angle of 50o. Calculate the angle between the incident and reflected ray","images":[],"options":{"A":"20o","B":"40o","C":"60o","D":"80o"},"answer":"D","explanation":"i = 90o - 50o = 40o  i = r  \u2234 total angle between i and r = 40o + 40o = 80o","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>27","subject":"Physics","year":"1996","type":"Objective","topic":"LIGHT WAVES : PLANE MIRROR","question":"A boy walks away from a plane mirror at a speed of 3 ms-1 in a direction normal to the plane of the mirror. At what speed is his image approaching him?","images":[],"options":{"A":"9.0 ms-1","B":"6.0 ms-1","C":"4.5 ms-1","D":"0.0 ms-1"},"answer":"B","explanation":"Velocity of image w.r.t boy = velocity of object - velocity of image    velocity w.r.t to boy = v - (-v)    = 3.0 - (-3.0)    The image velocity is 6.0 ms-1 towards the boy.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>28","subject":"Physics","year":"1996","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"The graph above shows the relationship between sin i and sin r for a ray of light in air incident on a liqiud surface. If i and r are respectively angles of incidence and refraction, deduce the refractive index of the liquid from the graph.","images":["data:image/png;base64,"],"options":{"A":"1.63","B":"1.50","C":"1.33","D":"1.25"},"answer":"D","explanation":"The refractive index is the slope of the graph  =1.0 - 0.20.8 - 0.18=0.80.62=1.25","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>29","subject":"Physics","year":"1996","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"When a ray of light is incident normally on an air-glass interface, its angle of refraction is","images":[],"options":{"A":"0o","B":"42o","C":"45o","D":"60o"},"answer":"A","explanation":"No refraction as it goes through at right angle to the surface of the glass prism.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1996>30","subject":"Physics","year":"1996","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"A ray of light is incident on a glass block as shown in the diagram above. If the reflected and refracted rays are perpendicular to each other, what is the refractive index of the glass relative to air?","images":["data:image/png;base64,"],"options":{"A":"1.65","B":"1.58","C":"1.52","D":"1.48"},"answer":"D","explanation":"angle of incidence = 56o (given)  angle of incidence = angle of reflection = 56o  angle of reflection + angle of refraction + 90o = 180o (sum of angles on a straight line)  \u2234 angle of reflection + angle of refraction = 90o  = 56o + angle of refraction = 90o  = angle of refraction = 90o - 56o = 34o  nair = 1  sin isin r=nglass1  sin 56osin 34o=nglass1  0.8290.559=nglass  \u2234 nglass relative to air = 1.48","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>31","subject":"Physics","year":"1996","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"The refractive index of a medium relative to air is 1.8. Calculate the critical angle for the medium correct to the nearest degree","images":[],"options":{"A":"18o","B":"34o","C":"45o","D":"68o"},"answer":"B","explanation":"The critical angle (c) can be calculated using the formula c = arcsin(1/n), where n is the refractive index. In this case, n = 1.8. Therefore, c = arcsin(1/1.8) = 34 degrees. The critical angle is the angle of incidence beyond which rays of light passing through a denser medium to the surface of a less dense medium are no longer refracted but totally internally reflected.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>32","subject":"Physics","year":"1996","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"A converging lens of focal length 5 cm forms a virtual image which is 10 cm from the lens. How far from the lens is the object?","images":[],"options":{"A":"2.0 cm","B":"3.3 cm","C":"5.0 cm","D":"10.0 cm"},"answer":"D","explanation":"f=5cm;v=10cm;u=?  1f=1v+1u  15=110+1u  1u=15-110  1u=2 - 110=110  \u2234u=10.0cm","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>33","subject":"Physics","year":"1996","type":"Objective","topic":"SOUND WAVES : SOURCES OF SOUND","question":"Which of the following instrument produces sound by the vibration of air column?","images":[],"options":{"A":"Piano","B":"Guitar","C":"Flute","D":"Handbell"},"answer":"C","explanation":"Flute players can change the pitch by changing the length of the tube (air column) with the fingers or by increasing the air speed in order to force the sound waves to the next note in the harmonic overtone series.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1996>34","subject":"Physics","year":"1996","type":"Objective","topic":"SOUND WAVES : ECHOES AND REVERBERATION","question":"The walls and ceilings of many standard auditoria are covered with perforated pads to","images":[],"options":{"A":"increase the intensity of sound waves","B":"increase the loudness of sound waves","C":"reduce the effect of reverbrations of sound waves","D":"increase the interference effect of sound waves"},"answer":"C","explanation":"Reverberation (also known as reverb), in acoustics, is a persistence of sound after it is produced. Reverberation is created when a sound or signal is reflected. This causes numerous reflections to build up and then decay as the sound is absorbed by the surfaces of objects in the space \u2013 which could include furniture, people, and air","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>35","subject":"Physics","year":"1996","type":"Objective","topic":"SOUND WAVES : VIBRATION IN STRINGS","question":"The string of length 1.0 m vibrates in 10 loops. If the total mass of the string is 1.0 x 10-3 kg and the tension in it is 10 N, calculate the frequency of the vibration.","images":[],"options":{"A":"50 Hz","B":"100 Hz","C":"250 Hz","D":"500 Hz"},"answer":"C","explanation":"fo =12l\u221aT\u03bc  T=10N;m=1.0x10-3kg;l=1.0m;\u03bc=ml=1.0 x 10-31.0=1.0x10-3kgm-1  fo =12 x 1\u221a101.0 x 10-3  fo =12\u221a10000  fo =12x 100  fo =50 Hz  Recall:10loops  10loops(10crestand10troughs)=102=5wavelengths  \u2234f=5fo=5x50=250Hz","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>36","subject":"Physics","year":"1996","type":"Objective","topic":"SOUND WAVES : SOURCES OF SOUND","question":"A siren has a disc of 64 holes and makes 20 revolutions per second. Calculate the frequency of the sound from the siren.","images":[],"options":{"A":"3.2 Hz","B":"16.0 Hz","C":"20.0 Hz","D":"1280.0 Hz"},"answer":"D","explanation":"The frequency of the sound from the siren can be calculated by multiplying the number of holes in the disc by the number of revolutions per second. This is because each revolution of the disc will produce a sound wave for each hole in the disc. Therefore, the frequency of the sound is 64 holes * 20 revolutions per second = 1280 Hz.","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>37","subject":"Physics","year":"1996","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH","question":"The distance between two successive crest of a water is 1 m. If a particle on the surface of the water makes two complete vertical oscillations in 1 second. Calculate the speed of the wave.","images":[],"options":{"A":"0.5 ms-1","B":"1.0 ms-1","C":"2.0 ms-1","D":"3.0 ms-1"},"answer":"C","explanation":"The speed of a wave is given by the product of its wavelength and frequency. In this case, the wavelength is the distance between two successive crests, which is 1 m, and the frequency is the number of complete oscillations per second, which is 2 Hz. Therefore, the speed of the wave is 1 m * 2 Hz = 2 ms-1.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>38","subject":"Physics","year":"1996","type":"Objective","topic":"SOUND WAVES : SPEED OF SOUND","question":"A sound wave of velocity 350 ms-1 is directed towards the surface of water. If the ratio of the wavelength of sound in water to that in air is 425 : 100, calculate the velocity of the wave in water.","images":[],"options":{"A":"82.4 ms-1","B":"148.8 ms-1","C":"350.0 ms-1","D":"1487.5 ms-1"},"answer":"D","explanation":"va = 350 ms-1  \u03bbw : \u03bba = 425 : 100 ==> \u03bba : \u03bbw = 100 : 425  vw = ?  vavw=f\u03bbaf\u03bbw==>vavw=\u03bba\u03bbw  350vw=100425==>350 x 425=100vw  \u2234vw=350 x 425100 = 148750100 = 1487.5 ms-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>39","subject":"Physics","year":"1996","type":"Objective","topic":"SOUND WAVES : SPEED OF SOUND","question":"The speed of sound in air is 330 ms-1. How far from the centre of a storm is an observer who hears a thunder clap 2 s after the lightning flash?  (Neglect the time taken by light to travel to the observer)","images":[],"options":{"A":"1320 m","B":"660 m","C":"600 m","D":"330 m"},"answer":"B","explanation":"v = 330 ms-1; t = 2 s; d = vt = 330 x 2 = 660 m","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>40","subject":"Physics","year":"1996","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : WAVEFORM","question":"The diagram below illustrates a variation of the displacement y of a wave particle with time t. If the velocity of the wave is 250 ms-1, calculate the distance between two successive particles which are in phase.","images":["data:image/png;base64,"],"options":{"A":"2.0 m","B":"2.5 m","C":"3.0 m","D":"5.0 m"},"answer":"D","explanation":"distance between two successive particles which are in phase = wavelength (\u03bb)  v = f\u03bb  \u2234\u03bb=vf=vT=250x0.02=5.0m","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>41","subject":"Physics","year":"1996","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH","question":"The diagram above represents a stationary wave set up in a string which is fixed at both ends. If the frequency of the wave is 256 Hz and the distance between N1 and N2 equals 1.5 m, calculate the speed of the wave.","images":["data:image/png;base64,"],"options":{"A":"128 ms-1","B":"192 ms-1","C":"384 ms-1","D":"768 ms-1"},"answer":"D","explanation":"L = 1/2\u03bb = 1.5 m; \u03bb = 2 x 1.5 = 3 m; f = 256 Hz; v = ?    v = f\u03bb = 256 x 3 = 768 ms-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>42","subject":"Physics","year":"1996","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : POWER","question":"Calculate the power delivered by a 3-phase line of its voltage and current are 132 KV and 60 A respectively.","images":[],"options":{"A":"2.38 x 107 W","B":"7.92 x 106 W","C":"3.96 x 106 W","D":"2.64 x 106 W"},"answer":"B","explanation":"V = 132 KV; I = 60 A; P = IV = 60 x 132000 = 7920000 = 7.92 x 106 W","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>43","subject":"Physics","year":"1996","type":"Objective","topic":"SOUND WAVES : TRANSMISSION OF SOUND WAVES","question":"The main portion of the mouth piece of a telephone is to convert sound energy into","images":[],"options":{"A":"Heat energy","B":"light energy","C":"chemical energy","D":"electrical energy"},"answer":"D","explanation":"The main function of the mouthpiece of a telephone is to convert sound energy into electrical energy. This is done through a process called transduction, where the sound waves cause a diaphragm to vibrate, which in turn moves a coil of wire in a magnetic field, generating an electrical signal.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1996>44","subject":"Physics","year":"1996","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CIRCUIT","question":"Which of the following is not a component of a d.c electric motor?","images":[],"options":{"A":"commutator","B":"field magnet","C":"slip rings","D":"armature"},"answer":"C","explanation":"Functionally, slip rings provide a continuous transfer of power, signals, or data. Specifically, in AC motors, they transfer resistance to the rotor windings. Commutators, on the other hand, are used in DC motors to reverse the polarity of current in the armature windings.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1996>45","subject":"Physics","year":"1996","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"The diagram below illustrates the conversions of a galvanometer of resistance 2 \u03a9 to an ammeter. The galvanometer gives a full-scale deflection for a current of 10 mA. Calculate the value of R.","images":["data:image/png;base64,"],"options":{"A":"2.0 x 103 \u03a9","B":"2.0 x 102 \u03a9","C":"2.0 x 10-1 \u03a9","D":"2.0 x 10-3 \u03a9"},"answer":"D","explanation":"Ig = 10 mA = 0.01 A  Is = 10 - 0.01 = 9.99 A  Rg = 2 \u03a9  Rs = ?  V = IR  Voltage in galvanometer = Voltage in shunt  Ig x Rg = Is x Rs  0.01 x 2 = 9.99Rs  0.02 = 9.99Rs  Rs=0.029.99=2.0x10-3\u03a9","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>46","subject":"Physics","year":"1996","type":"Objective","topic":"ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY","question":"A wire of length 100 cm and cross-sectional area 2.0 x 103 cm2 has a resistance of 0.10 \u03a9. Calculate its electrical conductivity","images":[],"options":{"A":"5.0 x 107 \u03a9-1cm-1","B":"5.0 x 106 \u03a9-1cm-1","C":"2.0 x 106 \u03a9-1cm-1","D":"5.0 x 105 \u03a9-1cm-1"},"answer":"D","explanation":"L = 100 cm; A = 2.0 x 10-3 cm2; R = 0.10 \u03a9; \u03c3 = ?  R\u03b1LA ==> R=\u03c1LA==> \u03c1=RALand \u03c3=1\u03c1  \u2234\u03c3=LRA=1000.10 x 2.0 x 10-3=5.0x105\u03a9-1cm-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>47","subject":"Physics","year":"1996","type":"Objective","topic":"ELECTROMAGNETIC FIELD : LENZ\u2019S LAW","question":"Lenz's law of electromagnetic induction states that","images":[],"options":{"A":"e.m.f is induced in the circuit whenever there is a change in the magnitude of flux linked with the circuit","B":"the induced current in a conductor is in such a direction as to oppose the change producing it","C":"the magnitude of the induced e.m.f in a circuit is proportional to the rate of change of the number of lines of force linking the circuit","D":"a force exerted on a current carrying conductor in a magnetic field"},"answer":"B","explanation":"Lenz's law, in electromagnetism, states that an induced electric current flows in a direction such that the current opposes the change that induced it. This law was deduced in 1834 by the Russian physicist Heinrich Friedrich Emil Lenz (1804\u201365).","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>48","subject":"Physics","year":"1996","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"A cell of e.m.f 1.5 V is connected in series with a resistor of resistance 3 \u03a9. A high-resistance voltmeter connected across the cell registers only 0.9 V. Calculate the internal resistance of the cell.","images":[],"options":{"A":"1.8 \u03a9","B":"2.0 \u03a9","C":"2.4 \u03a9","D":"4.5 \u03a9"},"answer":"B","explanation":"E = 1.5 V; R = 3 \u03a9; V = 0.9 V; r = ?; V = IR  \u2234I=VR=0.93=0.3A;FromI=ER + r=0.3  0.3=1.53 + r==>0.3(3+r)=1.5  = 0.9 + 0.3r = 1.5  = 0.3r = 1.5 - 0.9 = 0.6  \u2234r=0.60.3=2.0\u03a9","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>49","subject":"Physics","year":"1996","type":"Objective","topic":"MAGNETIC FIELD : USE OF ELECTROMAGNETS","question":"Soft iron is used in making the armature of an electric bell because it","images":[],"options":{"A":"retains it magnetism for a long time","B":"loses it magnetism","C":"produces permanet magnets","D":"is not easily magnetised"},"answer":"B","explanation":"The soft iron bar acquires the magnetic properties only when an electric current flows through the solenoid and loses the magnetic properties as soon as the current is switched off. Soft iron can be easily magnetized and demagnetized. That's why soft iron is used as the core of the electromagnet in an electric bell.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1996>50","subject":"Physics","year":"1996","type":"Objective","topic":"ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.","question":"The diagram beside illustrates an isolated metal sphere carrying charge W in a medium whose permitivity is \u03b5o. The magnitude of the electric field intensity P can be expressed as","images":["data:image/png;base64,"],"options":{"A":"Q24\u03c0\u03b5or2","B":"Q4\u03c0\u03b5or2","C":"Q4\u03c0\u03b5or","D":"Q24\u03c0\u03b5or"},"answer":"B","explanation":"P = Q4\u03c0\u03b5or2 it is measured in NC-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>51","subject":"Physics","year":"1996","type":"Objective","topic":"ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.","question":"The diagram beside illustrates an isolated metal sphere carrying charge W in a medium whose permitivity is \u03b5o. The magnitude of the electric field intensity P can be expressed as The electric potential of a point P in the diagram on Question above can be expressed as","images":["data:image/png;base64,"],"options":{"A":"Q24\u03c0\u03b5or","B":"Q4\u03c0\u03b5or2","C":"Q24\u03c0\u03b5or2","D":"Q4\u03c0\u03b5or"},"answer":"D","explanation":"It can be expressed as:       V = Q4\u03c0\u03b5or","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>52","subject":"Physics","year":"1996","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"Calculate the amount of heat generated in an external load of resistance 8 \u03a9, if an alternating current of peak value 5 A is passed through it for 100 s.","images":[],"options":{"A":"20,000 J","B":"10,000 J","C":"5,000 J","D":"4,000 J"},"answer":"B","explanation":"Io=5A;R=8\u03a9;t=100s  Ir.m.s=Io\u221a2=5\u221a2A  I2r.m.s=252A  H=I2r.m.sRt  \u2234H=252x8x100=25x4x100=10,000J","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>53","subject":"Physics","year":"1996","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE","question":"In the diagram below the resistor has a resistance of 8 \u03a9 while the reactance of the inductor and the capacitor are 10 \u03a9 and 16 \u03a9 respectively. Calculate the current in the circuit.","images":["data:image/png;base64,"],"options":{"A":"3.6 A","B":"3.8 A","C":"9.2 A","D":"13.0 A"},"answer":"D","explanation":"Z = \u221a(XL - XC)2 + R2 = \u221a(16 - 10)2 + 82  Z = \u221a62 + 82  Z = \u221a36 + 64 = \u221a100  Z = 10 \u03a9  V=IZ;I=VZ=13010=13.0A","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>54","subject":"Physics","year":"1996","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE","question":"The resistance in an R-C is 5 \u03a9. If the impedance of the circuit is 13 \u03a9. Calculate the reactance of the capacitor.","images":[],"options":{"A":"65 \u03a9","B":"18 \u03a9","C":"16 \u03a9","D":"12 \u03a9"},"answer":"D","explanation":"Z = 13 \u03a9 ==> Z = \u221aXC2 + R2    13 = \u221aXC2 + 52    132 = XC2 + 52    169 = XC2 + 25    XC2 = 169 - 25 = 144    XC = 12 \u03a9","marks":"1","difficulty":"3"},{"id":"objective>Physics>1996>55","subject":"Physics","year":"1996","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"What is the decay constant of a radioactive element whose half life is 3 seconds","images":[],"options":{"A":"0.132 s-1","B":"0.23 s-1","C":"0.347 s-1","D":"0.693 s-1"},"answer":"B","explanation":"t1/2=3s  t12=0.693\u03bb  \u03bb=0.693t1/2=0.6933=0.23s-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>56","subject":"Physics","year":"1996","type":"Objective","topic":"MOTION : VISCOSITY (FRICTION IN FLUIDS)","question":"Which of the following substance is most viscous at room temperature","images":[],"options":{"A":"Water","B":"Alcohol","C":"Petrol","D":"Palm Oil"},"answer":"D","explanation":"Viscosity is the property of a given liquid that describes its resistance to flow. A highly viscous fluid tends to be thick, like honey or cold maple syrup. Compared to a relatively non viscous fluid, such as water, highly viscous liquids flow much more slowly.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1996>57","subject":"Physics","year":"1996","type":"Objective","topic":"ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM","question":"Which of the following is not part of the electromagnetic spectrum?","images":[],"options":{"A":"Radio wave","B":"Gamma ray","C":"Infra-red ray","D":"Alpha particle"},"answer":"D","explanation":"Electromagnetic energy travels in waves and spans a broad spectrum from very long radio waves to very short gamma rays.   In order from highest to lowest energy, the sections of the EM spectrum are named: gamma rays, X-rays, ultraviolet radiation, visible light, infrared radiation, and radio waves.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1996>58","subject":"Physics","year":"1996","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"Which of the following is used in nuclear reactor to slow down fast-moving neutrons?","images":[],"options":{"A":"carbondioxide gas","B":"liquid sodium metal","C":"concrete shield","D":"graphite rods"},"answer":"D","explanation":"Graphite rods are used as moderators in a nuclear reactor. The primary reason that moderators are used in a nuclear reactor is to slow down the neutrons produced by fission.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>59","subject":"Physics","year":"1996","type":"Objective","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"Which of the following particles/rays do not originate from the nucleus of an atom?","images":[],"options":{"A":"Alpha particles","B":"Beta particles","C":"Gamma rays","D":"X-rays"},"answer":"D","explanation":"X-rays do not originate from the nucleus of an atom. They are produced when electrons in the outer shells of atoms fall into a lower energy level. The energy difference between the two levels is emitted as an X-ray. On the other hand, alpha particles, beta particles, and gamma rays are all products of nuclear reactions.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1996>60","subject":"Physics","year":"1996","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"The count rate of an alpha-particle source is 400 per minute. If the half-life of the source is 5 days, what would be the count rate per minute after 15 days.","images":[],"options":{"A":"20","B":"25","C":"50","D":"200"},"answer":"C","explanation":"Initial count rate = 400 per minute  t1/2 = 5 days  t = 15 days  Countrate=Initial count rate2NwhereNisthenumberofhalflives  N= tt1/2 = 155=3  Countrate=40023=4008=50perminute","marks":"1","difficulty":"3"}];